 41→const cacheDir = process.env.EVAL_CACHE_DIR ?? "eval-results/cache";
 42→const cachePath = join(cacheDir, "extraction-cache.json");
 43→const resultCache = loadCache(cachePath);
 44→const cases = JSON.parse(readFileSync(join(process.cwd(), "evals", "data", "golden-cases.json"), "utf8")) as GoldenCase[];
 45→assertAutoevalEnv();
 46→
 47→// strict_single is reserved for unambiguous one-entity probes.
 48→// Cases where multiple extractions are semantically valid should use multi_allowed.
 49→const intentScoreWeights: Record<
 50→  GoldenCaseIntent,
 51→  Record<
 52→    | "entity-precision"
 53→    | "entity-recall"
 54→    | "no-extra-entities"
 55→    | "no-phantom-persons"
 56→    | "evidence-grounded"
 57→    | "no-context-bleed"
 58→    | "evidence-source-current-message"
 59→    | "resolved-from-lineage"
