 61→    | "forbidden-kinds"
 62→    | "factuality"
 63→    | "relation-recall"
 64→    | "category-accuracy",
 65→    number
 66→  >
 67→> = {
 68→  strict_single: {
 69→    "entity-precision": 0.16,
 70→    "entity-recall": 0.16,
 71→    "no-extra-entities": 0.18,
 72→    "no-phantom-persons": 0.12,
 73→    "evidence-grounded": 0.08,
 74→    "no-context-bleed": 0.05,
 75→    "evidence-source-current-message": 0.05,
 76→    "resolved-from-lineage": 0.04,
 77→    "tool-filtering": 0.06,
 78→    "forbidden-kinds": 0.08,
 79→    factuality: 0.02,
 80→    "relation-recall": 0,
 81→    "category-accuracy": 0.1,
 82→  },
 83→  multi_allowed: {
 84→    "entity-precision": 0.21,
 85→    "entity-recall": 0.21,
 86→    "no-extra-entities": 0.05,
 87→    "no-phantom-persons": 0.11,
 88→    "evidence-grounded": 0.08,
 89→    "no-context-bleed": 0.04,
 90→    "evidence-source-current-message": 0.06,
 91→    "resolved-from-lineage": 0.04,
 92→    "tool-filtering": 0.04,
 93→    "forbidden-kinds": 0.06,
 94→    factuality: 0.02,
 95→    "relation-recall": 0.03,
 96→    "category-accuracy": 0.1,
 97→  },
 98→};
