135→  data: cases.map((testCase) => ({ input: testCase, expected: testCase })),
136→  task: async (input) => runCase(input),
137→  scorers: [
138→    entityPrecisionScorer,
139→    entityRecallScorer,
140→    noExtraEntitiesScorer,
141→    noPhantomPersonsScorer,
142→    evidenceGroundedScorer,
143→    noContextBleedScorer,
144→    evidenceSourceCurrentMessageScorer,
145→    resolvedFromLineageScorer,
146→    toolFilteringScorer,
147→    forbiddenKindsScorer,
148→    relationRecallScorer,
149→    categoryAccuracyScorer,
150→    factualityScorer,
151→  ],
152→  columns: ({ input, output, scores }) => [
153→    { label: "Case", value: input.id },
154→    { label: "Intent", value: input.intent },
155→    { label: "Ent", value: `${output.extractedEntities.length}/${input.expectedEntities.length}` },
156→    { label: "Prec", value: formatScoreCell(scoreByName(scores, "entity-precision")) },
157→    { label: "Rec", value: formatScoreCell(scoreByName(scores, "entity-recall")) },
158→    { label: "Cat", value: formatScoreCell(scoreByName(scores, "category-accuracy")) },
159→    {
160→      label: "Avg",
161→      value: computeWeightedAverage(input.intent, scores).toFixed(2),
162→    },
163→  ],
164→});
