209→function resolveEntityEvidenceSnippet(
210→  entityText: string,
211→  evidenceRows: Array<{ evidence?: string; fromText?: string; model?: string }>,
212→  fallbackInput: string,
213→): string {
214→  const normalizedEntityText = normalizeForSubstring(entityText);
215→  const matched = evidenceRows.find((row) => normalizeForSubstring(row.fromText ?? "") === normalizedEntityText);
216→  const snippet = matched?.evidence ?? evidenceRows[0]?.evidence ?? fallbackInput;
217→  return snippet.trim().length > 0 ? snippet : fallbackInput;
218→}
