110→const factualityScorer = createScorer<GoldenCase, ExtractionEvalOutput, GoldenCase>({
111→  name: "factuality",
112→  description: "Average factual grounding score for extracted entity texts against matched provenance evidence snippets.",
113→  scorer: async ({ input, output }) => {
114→    if (output.extractedEntities.length === 0) {
115→      return { score: 1 };
116→    }
117→
118→    let total = 0;
119→    for (const entity of output.extractedEntities) {
120→      const snippet = resolveEntityEvidenceSnippet(entity.text, output.evidenceRows, input.input);
121→      const result = await Factuality({
122→        input: snippet,
123→        output: entity.text,
124→        expected: snippet,
125→        model: autoevalModel,
126→      });
127→      total += result.score ?? 0;
128→    }
129→
130→    return { score: total / output.extractedEntities.length };
131→  },
132→});
