151→  ],
152→  columns: ({ input, output, scores }) => [
153→    { label: "Case", value: input.id },
154→    { label: "Intent", value: input.intent },
155→    { label: "Ent", value: `${output.extractedEntities.length}/${input.expectedEntities.length}` },
156→    { label: "Prec", value: formatScoreCell(scoreByName(scores, "entity-precision")) },
157→    { label: "Rec", value: formatScoreCell(scoreByName(scores, "entity-recall")) },
158→    { label: "Cat", value: formatScoreCell(scoreByName(scores, "category-accuracy")) },
159→    {
160→      label: "Avg",
161→      value: computeWeightedAverage(input.intent, scores).toFixed(2),
162→    },
163→  ],
164→});
165→
166→function scoreByName(
167→  scores: Array<{ name: string; score: number | null }>,
168→  name: string,
169→): number {
170→  const match = scores.find((score) => score.name === name);
171→  if (!match || match.score === null || Number.isNaN(match.score)) {
172→    throw new Error(`Missing score for scorer: ${name}`);
173→  }
174→
175→  return match.score;
176→}
177→
178→function formatScoreCell(value: number): string {
179→  return value.toFixed(2);
180→}
181→
182→function computeWeightedAverage(
183→  intent: GoldenCaseIntent,
184→  scores: Array<{ name: string; score: number | null }>,
185→): number {
186→  const weights = intentScoreWeights[intent];
187→  if (!weights) {
188→    throw new Error(`Unknown golden case intent: ${intent}`);
189→  }
190→
191→  let weightedTotal = 0;
192→  let weightTotal = 0;
193→  for (const [scorerName, weight] of Object.entries(weights)) {
194→    if (weight <= 0) {
195→      continue;
196→    }
197→
198→    weightedTotal += scoreByName(scores, scorerName) * weight;
199→    weightTotal += weight;
200→  }
201→
202→  if (weightTotal === 0) {
203→    throw new Error(`No scorer weights configured for intent: ${intent}`);
204→  }
205→
206→  return weightedTotal / weightTotal;
207→}
208→
209→function resolveEntityEvidenceSnippet(
210→  entityText: string,
211→  evidenceRows: Array<{ evidence?: string; fromText?: string; model?: string }>,
212→  fallbackInput: string,
213→): string {
214→  const normalizedEntityText = normalizeForSubstring(entityText);
215→  const matched = evidenceRows.find((row) => normalizeForSubstring(row.fromText ?? "") === normalizedEntityText);
216→  const snippet = matched?.evidence ?? evidenceRows[0]?.evidence ?? fallbackInput;
217→  return snippet.trim().length > 0 ? snippet : fallbackInput;
218→}
