220→async function runCase(testCase: GoldenCase): Promise<ExtractionEvalOutput> {
221→  const cacheKey = buildCaseCacheKey(extractionModel, testCase);
222→  const cached = resultCache[cacheKey];
223→  if (cached) {
224→    return {
225→      ...cached,
226→      extractedTools: cached.extractedTools ?? [],
227→      extractedRelations: cached.extractedRelations ?? [],
228→    };
229→  }
230→
231→  const { workspaceRecord, workspaceName, projectRecord, conversationRecord, ownerPersonCount } = await seedWorkspace(runtime.surreal, testCase.workspace_name);
232→  const conversationId = conversationRecord.id as string;
233→  const seededContext = testCase.context ?? [];
234→  const contextMessageIds = seededContext.length > 0
235→    ? await seedConversationContext(runtime.surreal, conversationRecord, seededContext)
236→    : [];
237→
238→  if (testCase.workspace_seed && testCase.workspace_seed.length > 0) {
239→    await seedGraphEntities(runtime.surreal, workspaceRecord, projectRecord, conversationRecord, testCase.workspace_seed);
240→  }
241→
242→  const userMessageRecord = await seedUserMessage(runtime.surreal, conversationRecord, testCase.input);
243→
244→  const extractionConversationContext = await loadExtractionConversationContext({
245→    surreal: runtime.surreal,
246→    conversationId,
247→    currentMessageRecord: userMessageRecord,
248→  });
249→  const extractionGraphContext = await loadConversationGraphContext(runtime.surreal, conversationId, 60);
250→  const workspaceProjects = await loadWorkspaceProjects(runtime.surreal, workspaceRecord);
251→  const workspaceProjectNames = workspaceProjects.map((project) => project.name);
252→
253→  const extraction = await extractStructuredGraph({
254→    extractionModel: runtime.extractionModel,
255→    conversationHistory: extractionConversationContext.conversationHistory,
256→    currentMessage: extractionConversationContext.currentMessage,
257→    graphContext: extractionGraphContext,
258→    sourceText: testCase.input,
259→    onboarding: true,
260→    workspaceName,
261→    projectNames: workspaceProjectNames,
262→  });
263→
264→  const now = new Date();
265→  const persistence = await persistExtractionOutput({
266→    surreal: runtime.surreal,
267→    embeddingModel: runtime.embeddingModel,
268→    embeddingDimension: runtime.config.embeddingDimension,
269→    extractionModelId: runtime.config.extractionModelId,
270→    extractionStoreThreshold: runtime.config.extractionStoreThreshold,
271→    workspaceRecord,
272→    sourceRecord: userMessageRecord as SourceRecord,
273→    sourceKind: "message",
274→    sourceLabel: testCase.input.slice(0, 140),
275→    promptText: testCase.input,
276→    output: extraction,
277→    sourceMessageRecord: userMessageRecord,
278→    extractionHistoryMessageIds: extractionConversationContext.conversationHistory.map(
279→      (row) => row.id.id as string,
280→    ),
281→    now,
282→  });
283→
284→  await appendExtractedTools(runtime.surreal, workspaceRecord, persistence.tools, now);
285→
286→  const [evidenceRows] = await runtime.surreal
287→    .query<[Array<{
288→      evidence?: string;
289→      from_text?: string;
290→      model?: string;
291→      evidence_source?: RecordId<"message", string>;
292→      resolved_from?: RecordId<"message", string>;
293→    }>]>(
294→      "SELECT evidence, from_text, model, evidence_source, resolved_from FROM extraction_relation WHERE `in` = $source;",
295→      { source: userMessageRecord },
296→    )
297→    .collect<[Array<{
298→      evidence?: string;
299→      from_text?: string;
300→      model?: string;
301→      evidence_source?: RecordId<"message", string>;
302→      resolved_from?: RecordId<"message", string>;
303→    }>]>();
304→
305→  const personCount = await loadWorkspacePeopleCount(runtime.surreal, workspaceRecord);
306→  const [workspaceToolRows] = await runtime.surreal
307→    .query<[Array<{ tools?: string[] }>]>("SELECT tools FROM $workspace LIMIT 1;", {
308→      workspace: workspaceRecord,
309→    })
310→    .collect<[Array<{ tools?: string[] }>]>();
311→  const extractedTools = workspaceToolRows[0]?.tools ?? [];
312→
313→  const [relationRows] = await runtime.surreal
314→    .query<[Array<{
315→      kind: string;
316→      in: { tb: string };
317→      out: { tb: string };
318→      from_text: string;
319→      to_text: string;
320→      confidence: number;
321→    }>]>(
322→      "SELECT kind, `in`, out, from_text, to_text, confidence FROM entity_relation WHERE source_message = $source AND kind != 'POSSIBLE_DUPLICATE';",
323→      { source: userMessageRecord },
324→    )
325→    .collect<[Array<{
326→      kind: string;
327→      in: { tb: string };
328→      out: { tb: string };
329→      from_text: string;
330→      to_text: string;
331→      confidence: number;
332→    }>]>();
333→
334→  const output: ExtractionEvalOutput = {
335→    caseId: testCase.id,
336→    input: testCase.input,
337→    userMessageId: userMessageRecord.id as string,
338→    contextMessageIds,
339→    extractedEntities: persistence.entities.map((e) => ({
340→      kind: e.kind,
341→      text: e.text,
342→      confidence: e.confidence,
343→      ...(e.category ? { category: e.category } : {}),
344→    })),
345→    extractedTools,
346→    personCount,
347→    ownerPersonCount,
348→    evidenceRows: evidenceRows.map((row) => ({
349→      evidence: row.evidence,
350→      fromText: row.from_text,
351→      model: row.model,
352→      evidenceSourceId: row.evidence_source?.id as string | undefined,
353→      resolvedFromId: row.resolved_from?.id as string | undefined,
354→    })),
355→    extractedRelations: relationRows.map((row) => ({
356→      kind: row.kind,
357→      fromKind: row.in.tb,
358→      fromText: row.from_text,
359→      toKind: row.out.tb,
360→      toText: row.to_text,
361→      confidence: row.confidence,
362→    })),
363→  };
364→
365→  resultCache[cacheKey] = output;
366→  saveCache(cachePath, resultCache);
367→  return output;
368→}
