385→  const hasBraintrustKey = hasEnv("BRAINTRUST_API_KEY");
386→  if (!hasOpenAiKey && !hasBraintrustKey) {
387→    throw new Error(
388→      "Missing evaluator credentials. Set OPENAI_API_KEY (recommended for OPENAI_BASE_URL/OpenRouter) or BRAINTRUST_API_KEY.",
