410→function buildCaseCacheKey(modelId: string, testCase: GoldenCase): string {
411→  const cacheVersion = "classification-v3";
412→  const caseHash = createHash("sha256").update(JSON.stringify(testCase)).digest("hex").slice(0, 24);
413→  return `${cacheVersion}:${modelId}:${testCase.id}:${caseHash}`;
