 1→import { createScorer } from "evalite";
 2→import type { GoldenCase, ExtractionEvalOutput } from "../types";
 3→import { matchesExpectedEntity } from "./shared";
 4→
 5→export const noExtraEntitiesScorer = createScorer<GoldenCase, ExtractionEvalOutput, GoldenCase>({
 6→  name: "no-extra-entities",
 7→  description: "Strict scorer for strict_single cases: requires exact expected set with no extra entities.",
 8→  scorer: ({ output, expected }) => {
 9→    if (expected.intent !== "strict_single") {
10→      return { score: 1 };
11→    }
12→
13→    const expectedEntities = expected.expectedEntities;
14→    const extractedEntities = output.extractedEntities;
15→    if (expectedEntities.length !== extractedEntities.length) {
16→      return { score: 0 };
17→    }
18→
19→    const unmatchedExpected = [...expectedEntities];
20→    for (const entity of extractedEntities) {
21→      const matchedIndex = unmatchedExpected.findIndex((candidate) => matchesExpectedEntity(candidate, entity, 0.5));
22→
23→      if (matchedIndex === -1) {
24→        return { score: 0 };
25→      }
26→
27→      unmatchedExpected.splice(matchedIndex, 1);
28→    }
29→
30→    return { score: unmatchedExpected.length === 0 ? 1 : 0 };
31→  },
32→});
